-- by { rfl } 自動證明計算等式
theorem addZero_compute : add zero (succ zero) ≡ succ zero :=
  by { rfl }

-- by { simp } 自動簡化
theorem simp_example : add zero (succ zero) ≡ succ zero :=
  by { simp }

-- by { induction } 做歸納證明
-- 自動拆成 zero 和 succ 兩個子目標
theorem myAddZeroR_tac (n : Nat) : add n zero ≡ n := by {
  induction n;
  exact refl;
  rewrite ih;
  exact refl
}

